@Service
@RequiredArgsConstructor
public class PaymentServiceImpl implements PaymentService {
    private final PaymentRepository paymentRepository;
    private final UserRepository userRepository;

    @Override
    public PaymentData processPayment(PaymentData payment) {
        // Validate user exists
        Optional<UserEntity> userOpt = userRepository.findById(payment.getUserId());
        if (!userOpt.isPresent()) {
            throw new RuntimeException("User not found: " + payment.getUserId());
        }
        UserEntity user = userOpt.get();

        // Check balance
        if (user.getBalance().compareTo(payment.getAmount()) < 0) {
            throw new RuntimeException("Insufficient balance");
        }

        // Check payment is not duplicate
        if (paymentRepository.existsByTransactionId(payment.getTransactionId())) {
            throw new RuntimeException("Duplicate transaction");
        }

        // Save payment
        PaymentEntity entity = new PaymentEntity();
        entity.setUserId(payment.getUserId());
        entity.setAmount(payment.getAmount());
        entity.setTransactionId(payment.getTransactionId());
        entity.setStatus("PENDING");
        PaymentEntity saved = paymentRepository.save(entity);

        PaymentData result = new PaymentData();
        result.setId(saved.getId());
        result.setStatus(saved.getStatus());
        return result;
    }
}
